INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES (0, 0, 6006, "あたしも教官の仕事を\n頑張れば、あいつに\n喜んでもらえたり\nするのかな…", 0.3, 1, 129811, 8, 0, 11, 6);
INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES ("", "", 6007, "", "", "", 0, "", "", 91, 6);
