INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES (0, 0, 6011, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 0.8, 1, 129911, 6, 0, 11, 6);
INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES ("", "", 6012, "", "", "", 0, "", "", 91, 6);
