INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES (0, 0, 6016, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 0.3, 1, 129811, 9, 0, 11, 6);
