INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES (0, 0, 7006, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 0.3, 1, 129911, 6, 0, 11, 7);
INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES ("", "", 7007, "", "", "", 0, "", "", 91, 7);
