INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES (0, 0, 7011, "エリコ班の急成長は\n騎士団の中でも話題に\nなってたからな\nホントすげえ奴等だよ", 0, 1, 129811, 6, 0, 11, 7);
