INSERT INTO `v1_7fda521da8302ef50adf5506604986a97dc66fcf1475e4f1666d4e224b3cc3c3` VALUES (0, 0, 7016, "彼らが私に逆らわずに\n努力したからこそ、\n得たものもありますし\n…感謝しておきますわ", 0.5, 1, 129911, 6, 0, 11, 7);
